SELECT COUNT(*) 
   FROM firewall_rules 
   WHERE enabled = 1;

SELECT moved_by, COUNT(rule_id) AS rule_moves
FROM rule_movements
GROUP BY moved_by;

SELECT rule_id, description
FROM firewall_rules
WHERE enabled = 1;

SELECT node_id, COUNT(rule_id) AS rule_count
FROM firewall_rules
GROUP BY node_id;

SELECT change_description
FROM rule_changes
WHERE rule_id = 1;

SELECT changed_by, COUNT(*) AS number_of_changes
FROM rule_changes
GROUP BY changed_by;

SELECT 
    (SELECT COUNT(*) FROM rule_changes) + 
    (SELECT COUNT(*) FROM rule_movements) AS total_rule_changes_and_movements;

SELECT u.user_name, rm.movement_date
FROM rule_movements rm
JOIN users u ON rm.moved_by = u.user_id;
